SELECT CASE WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NOT NULL AND DATEDIFF(day, demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) >= :param_1 OR demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NOT NULL AND DATEDIFF(day, demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) < :param_2) THEN DATEFROMPARTS(YEAR(demo_retail.dbo.orders.order_date), MONTH(demo_retail.dbo.orders.order_date), 1) ELSE NULL END AS event_month, CASE WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NOT NULL AND DATEDIFF(day, demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) < :param_2) THEN :param_3 WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NOT NULL AND DATEDIFF(day, demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) >= :param_1 AND DATEDIFF(day, demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) > :param_4) THEN :param_5 WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NOT NULL AND DATEDIFF(day, demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) >= :param_1 AND DATEDIFF(day, demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) < :param_6) THEN :param_7 WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NOT NULL AND DATEDIFF(day, demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) >= :param_1) THEN DATEDIFF(day, demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) ELSE NULL END AS lag_day, CAST(demo_retail.dbo.orders.loaded_at AS DATE) AS load_epoch_day, CAST(NULL AS VARCHAR(max)) AS batch_id, CAST(NULL AS VARCHAR(max)) AS alt_value, CASE WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NOT NULL AND DATEDIFF(day, demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) >= :param_1) THEN :param_8 ELSE :param_9 END AS is_eligible, CASE WHEN (demo_retail.dbo.orders.order_date IS NULL) THEN :param_10 ELSE :param_11 END AS is_null_event_time, CASE WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NULL) THEN :param_12 ELSE :param_13 END AS is_null_load_time_only, CASE WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NOT NULL AND DATEDIFF(day, demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) >= :param_14 AND DATEDIFF(day, demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) < :param_15) THEN :param_16 ELSE :param_17 END AS is_negative_clipped, CASE WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NOT NULL AND DATEDIFF(day, demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) < :param_2) THEN :param_18 ELSE :param_19 END AS is_negative_lag_excluded, CASE WHEN (demo_retail.dbo.orders.order_date IS NOT NULL AND demo_retail.dbo.orders.loaded_at IS NOT NULL AND DATEDIFF(day, demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) >= :param_1 AND DATEDIFF(day, demo_retail.dbo.orders.order_date, demo_retail.dbo.orders.loaded_at) > :param_20) THEN :param_21 ELSE :param_22 END AS is_overflow, CAST(:param_23 AS INTEGER) AS is_join_unmatched, CAST(:param_24 AS INTEGER) AS is_base_row, CAST(:param_25 AS INTEGER) AS is_ambiguous_base, CAST(:param_26 AS INTEGER) AS is_compare_mismatch, CAST(NULL AS INTEGER) AS lookup_dup, CAST(NULL AS VARCHAR(max)) AS key_hash, demo_retail.dbo.orders.loaded_at AS load_time  INTO #mp_probe 
FROM demo_retail.dbo.orders 
WHERE demo_retail.dbo.orders.loaded_at <= :as_of OR demo_retail.dbo.orders.loaded_at IS NULL
